import asyncio
import websockets
import json
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.players = {}
        self.item_ownership = defaultdict(set)  # item_id -> set of player_ids
        self.server_inventory = {i: None for i in range(1, 101)}  # Example inventory

    async def register(self, websocket, path):
        player_id = None
        try:
            async for message in websocket:
                data = json.loads(message)
                action = data.get("action")

                if action == "register":
                    player_id = data["player_id"]
                    self.players[player_id] = websocket
                    await self.send_inventory(player_id)

                elif action == "trade":
                    await self.handle_trade(data)

        except websockets.ConnectionClosed:
            if player_id:
                del self.players[player_id]

    async def send_inventory(self, player_id):
        inventory = {item_id: owner for item_id, owner in self.server_inventory.items() if owner == player_id}
        await self.players[player_id].send(json.dumps({"action": "update_inventory", "inventory": inventory}))

    async def handle_trade(self, data):
        from_player = data["from_player"]
        to_player = data["to_player"]
        item_id = data["item_id"]

        if self.server_inventory[item_id] == from_player:
            if to_player in self.players:
                self.server_inventory[item_id] = to_player
                await self.send_inventory(from_player)
                await self.send_inventory(to_player)
                await self.notify_trade_success(from_player, to_player, item_id)
            else:
                await self.notify_error(from_player, "Recipient player not connected.")
        else:
            await self.notify_error(from_player, "Item not owned by you.")

    async def notify_trade_success(self, from_player, to_player, item_id):
        msg = json.dumps({"action": "trade_success", "item_id": item_id, "to_player": to_player})
        await self.players[from_player].send(msg)
        await self.players[to_player].send(msg)

    async def notify_error(self, player_id, error_message):
        await self.players[player_id].send(json.dumps({"action": "error", "message": error_message}))

async def main():
    server = GameServer()
    async with websockets.serve(server.register, "localhost", 6789):
        await asyncio.Future()  # Run server forever

asyncio.run(main())